import React, { useCallback, useEffect, useMemo, useState } from "react";
import DataGrid from "./components/DataGrid";
import { fetchStocks, simulateTick } from "./services/api";
import { createInventoryConnection } from "./services/signalr";
import "./App.css";

function App() {
  const [stocks, setStocks] = useState([]);
  const [status, setStatus] = useState("disconnected");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [lastTick, setLastTick] = useState(null);

  const loadStocks = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const data = await fetchStocks();
      setStocks(data);
    } catch (err) {
      setError("Failed to load stocks. Random failure may have occurred.");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleSimulate = useCallback(async () => {
    setError("");
    try {
      const updated = await simulateTick();
      if (updated && updated.id) {
        setStocks((prev) => prev.map((item) => (item.id === updated.id ? updated : item)));
        setLastTick(updated.symbol);
      }
    } catch (err) {
      setError("Simulation failed due to random API failure. Try again.");
    }
  }, []);

  useEffect(() => {
    loadStocks();
  }, [loadStocks]);

  useEffect(() => {
    const connection = createInventoryConnection();
    setStatus("connecting");

    connection.on("stockCreated", (stock) => {
      setStocks((prev) => {
        if (prev.some((item) => item.id === stock.id)) {
          return prev;
        }
        return [...prev, stock].sort((a, b) => a.id - b.id);
      });
    });

    connection.on("stockUpdated", (stock) => {
      setStocks((prev) => prev.map((item) => (item.id === stock.id ? stock : item)));
    });

    connection.on("stockDeleted", (id) => {
      setStocks((prev) => prev.filter((item) => item.id !== id));
    });

    connection
      .start()
      .then(() => setStatus("connected"))
      .catch(() => setStatus("disconnected"));

    connection.onreconnected(() => setStatus("connected"));
    connection.onreconnecting(() => setStatus("reconnecting"));
    connection.onclose(() => setStatus("disconnected"));

    return () => {
      connection.stop();
    };
  }, []);

  const columns = useMemo(
    () => [
      { key: "id", label: "ID", width: "70px" },
      { key: "symbol", label: "Symbol", width: "110px" },
      { key: "company", label: "Company", width: "1.6fr" },
      {
        key: "price",
        label: "Price",
        width: "120px",
        format: (value) => `$${Number(value).toFixed(2)}`
      },
      { key: "shares", label: "Shares", width: "110px" },
      {
        key: "updatedAtUtc",
        label: "Last Updated",
        width: "1.4fr",
        format: (value) => new Date(value).toLocaleString()
      }
    ],
    []
  );

  return (
    <div className="page">
      <header className="header">
        <div>
          <p className="eyebrow">Live Stocks</p>
          <h1>Stock Ticker Dashboard</h1>
          <p className="subtitle">SignalR updates with 10% random API failures.</p>
        </div>
        <div className="status-card">
          <div>
            <span className={`status-dot ${status}`} />
            <span className="status-text">{status}</span>
          </div>
          <div className="actions">
            <button className="refresh" onClick={loadStocks}>
              Refresh
            </button>
            <button className="refresh secondary" onClick={handleSimulate}>
              Simulate Tick
            </button>
          </div>
        </div>
      </header>

      {loading && <div className="notice">Loading stocks...</div>}
      {error && <div className="notice error">{error}</div>}
      {lastTick && <div className="notice">Last tick: {lastTick}</div>}

      <DataGrid columns={columns} rows={stocks} />
    </div>
  );
}

export default App;
